@prefix topo: <https://purl.org/geojson/topo#> .

[] a topo:Edge ;
    topo:relatedFeatures ( [ ns1:relation <http://www.iana.org/assignments/relation/topology> ;
                prof:hasRole <geof:sfTouches> ;
                oa:hasTarget <http://www.example.com/features/L2> ] ),
